import java.text.NumberFormat;
import java.util.Locale;

abstract class BankAccount {
    protected String accountNumber;
    protected String accountHolder;
    protected double balance;
    protected static int totalAccounts = 0;

    BankAccount(String accountNumber, String accountHolder, double initialBalance) {
        this.accountNumber = accountNumber;
        this.accountHolder = accountHolder;
        this.balance = initialBalance;
        totalAccounts++;
        System.out.println("Account created: " + accountNumber);
    }

    // Abstract methods
    abstract double calculateInterest();
    abstract void withdraw(double amount);
    abstract void deposit(double amount);
    abstract void displayBalance();

    // Concrete methods
    void displayAccountInfo() {
        System.out.println("Account Number: " + accountNumber);
        System.out.println("Account Holder: " + accountHolder);
        System.out.println("Balance: " + formatCurrency(balance));
    }

    String formatCurrency(double amount) {
        NumberFormat formatter = NumberFormat.getCurrencyInstance(new Locale("en", "IN"));
        return formatter.format(amount);
    }

    static int getTotalAccounts() {
        return totalAccounts;
    }
}

class SavingsAccount extends BankAccount {
    private double interestRate;
    private double minimumBalance;

    SavingsAccount(String accountNumber, String accountHolder, 
                   double initialBalance, double interestRate, double minimumBalance) {
        super(accountNumber, accountHolder, initialBalance);
        this.interestRate = interestRate;
        this.minimumBalance = minimumBalance;
    }

    @Override
    double calculateInterest() {
        double interest = balance * interestRate / 100;
        System.out.println("Interest calculated: " + formatCurrency(interest) + 
                          " at " + interestRate + "%");
        return interest;
    }

    @Override
    void withdraw(double amount) {
        if (amount > balance) {
            System.out.println("Insufficient balance!");
        } else if (balance - amount < minimumBalance) {
            System.out.println("Cannot withdraw! Minimum balance of " + 
                             formatCurrency(minimumBalance) + " required.");
        } else {
            balance -= amount;
            System.out.println("Withdrawn: " + formatCurrency(amount));
            System.out.println("New balance: " + formatCurrency(balance));
        }
    }

    @Override
    void deposit(double amount) {
        balance += amount;
        System.out.println("Deposited: " + formatCurrency(amount));
        System.out.println("New balance: " + formatCurrency(balance));
    }

    @Override
    void displayBalance() {
        System.out.println("=== Savings Account ===");
        displayAccountInfo();
        System.out.println("Interest Rate: " + interestRate + "%");
        System.out.println("Minimum Balance: " + formatCurrency(minimumBalance));
    }
}

class CurrentAccount extends BankAccount {
    private double overdraftLimit;

    CurrentAccount(String accountNumber, String accountHolder, 
                   double initialBalance, double overdraftLimit) {
        super(accountNumber, accountHolder, initialBalance);
        this.overdraftLimit = overdraftLimit;
    }

    @Override
    double calculateInterest() {
        System.out.println("Current accounts do not earn interest.");
        return 0;
    }

    @Override
    void withdraw(double amount) {
        double availableBalance = balance + overdraftLimit;
        if (amount > availableBalance) {
            System.out.println("Overdraft limit exceeded!");
        } else {
            balance -= amount;
            System.out.println("Withdrawn: " + formatCurrency(amount));
            System.out.println("New balance: " + formatCurrency(balance));
            if (balance < 0) {
                System.out.println("Warning: Overdraft used. Balance negative.");
            }
        }
    }

    @Override
    void deposit(double amount) {
        balance += amount;
        System.out.println("Deposited: " + formatCurrency(amount));
        System.out.println("New balance: " + formatCurrency(balance));
    }

    @Override
    void displayBalance() {
        System.out.println("=== Current Account ===");
        displayAccountInfo();
        System.out.println("Overdraft Limit: " + formatCurrency(overdraftLimit));
    }
}

class FixedDepositAccount extends BankAccount {
    private int tenureMonths;
    private double fixedInterestRate;
    private boolean matured;

    FixedDepositAccount(String accountNumber, String accountHolder,
                        double initialBalance, int tenureMonths, double fixedInterestRate) {
        super(accountNumber, accountHolder, initialBalance);
        this.tenureMonths = tenureMonths;
        this.fixedInterestRate = fixedInterestRate;
        this.matured = false;
    }

    @Override
    double calculateInterest() {
        if (!matured) {
            double interest = balance * fixedInterestRate * tenureMonths / 1200;
            System.out.println("FD Interest calculated: " + formatCurrency(interest));
            return interest;
        }
        return 0;
    }

    @Override
    void withdraw(double amount) {
        if (!matured) {
            System.out.println("Cannot withdraw before maturity! Tenure: " + 
                             tenureMonths + " months");
        } else if (amount > balance) {
            System.out.println("Insufficient balance!");
        } else {
            balance -= amount;
            System.out.println("Withdrawn: " + formatCurrency(amount));
            System.out.println("Remaining balance: " + formatCurrency(balance));
        }
    }

    @Override
    void deposit(double amount) {
        System.out.println("Additional deposits not allowed in FD account.");
    }

    @Override
    void displayBalance() {
        System.out.println("=== Fixed Deposit Account ===");
        displayAccountInfo();
        System.out.println("Tenure: " + tenureMonths + " months");
        System.out.println("Interest Rate: " + fixedInterestRate + "%");
        System.out.println("Matured: " + (matured ? "Yes" : "No"));
    }

    void mature() {
        if (!matured) {
            double interest = calculateInterest();
            balance += interest;
            matured = true;
            System.out.println("FD Matured! Interest added. Final balance: " + 
                             formatCurrency(balance));
        }
    }
}

public class BankSystemDemo {
    public static void main(String[] args) {
        System.out.println("=== Bank Account Management System ===\n");

        // Runtime polymorphism - array of abstract class
        BankAccount[] accounts = {
            new SavingsAccount("SAV001", "Rajesh Kumar", 50000, 4.5, 5000),
            new CurrentAccount("CUR001", "Priya Sharma", 100000, 50000),
            new FixedDepositAccount("FD001", "Amit Patel", 200000, 12, 7.5)
        };

        // Demonstrate polymorphic behavior
        for (BankAccount account : accounts) {
            System.out.println("\n" + "=".repeat(50));
            account.displayBalance();
            account.calculateInterest();
            account.deposit(10000);
            account.withdraw(25000);
        }

        // Special handling for FD
        FixedDepositAccount fd = (FixedDepositAccount) accounts[2];
        System.out.println("\n" + "=".repeat(50));
        fd.mature();  // Mature the FD
        fd.displayBalance();
        fd.withdraw(100000);

        System.out.println("\n=== Total Accounts: " + BankAccount.getTotalAccounts());
    }
}
