// 1. SINGLE INHERITANCE
class ElectronicDevice {
    protected String brand;
    protected boolean isOn;

    ElectronicDevice(String brand) {
        this.brand = brand;
        this.isOn = false;
    }

    void turnOn() {
        isOn = true;
