    Laptop(String brand, int ramSize) {
        super(brand);
        this.ramSize = ramSize;
    }

    void code() {
        if (isOn) {
            System.out.println("Coding on " + brand + " laptop with " + ramSize + "GB RAM");
        }
    }
}

// 2. MULTILEVEL INHERITANCE
class Animal {
    void eat() {
        System.out.println("Animal eats");
    }
}

class Mammal extends Animal {  // Level 2
    void breathe() {
        System.out.println("Mammal breathes air");
    }
}

class Dog extends Mammal {  // Level 3
    void bark() {
        System.out.println("Dog barks");
    }
}

// 3. HIERARCHICAL INHERITANCE
class Shape {
    void draw() {
        System.out.println("Drawing shape");
    }
}

class Circle extends Shape {  // Child 1
    void drawCircle() {
        System.out.println("Drawing circle");
    }
}

class Rectangle extends Shape {  // Child 2
    void drawRectangle() {
        System.out.println("Drawing rectangle");
    }
}

class Triangle extends Shape {  // Child 3
    void drawTriangle() {
        System.out.println("Drawing triangle");
    }
}

// 4. WHY MULTIPLE INHERITANCE IS NOT SUPPORTED
// The Diamond Problem:
/*
class A {
    void display() { System.out.println("A"); }
}
class B {
    void display() { System.out.println("B"); }
}
// class C extends A, B { }  // ERROR! Which display() to inherit?
*/

// 5. SOLUTION: Using interfaces for multiple inheritance
interface Flyable {
    void fly();
    default void show() {
        System.out.println("Can fly");
    }
}

interface Swimmable {
    void swim();
    default void show() {
        System.out.println("Can swim");
    }
}

interface Walkable {
    void walk();
}

// Multiple interface inheritance (allowed)
class Duck implements Flyable, Swimmable, Walkable {
    @Override
    public void fly() {
        System.out.println("Duck flies");
    }

    @Override
    public void swim() {
        System.out.println("Duck swims");
    }

    @Override
    public void walk() {
        System.out.println("Duck walks");
    }

    // Resolve default method conflict
    @Override
    public void show() {
        Flyable.super.show();
        Swimmable.super.show();
        System.out.println("Duck can do everything!");
    }
}

// Interface inheritance (multiple interface inheritance)
interface A { void methodA(); }
interface B { void methodB(); }
interface C extends A, B {  // Valid - interface can extend multiple interfaces
    void methodC();
}

class Implementation implements C {
    public void methodA() { System.out.println("Method A"); }
    public void methodB() { System.out.println("Method B"); }
    public void methodC() { System.out.println("Method C"); }
}

// Real-world example: Smart Device with multiple capabilities
interface Camera {
    void takePhoto();
}

interface MusicPlayer {
    void playMusic();
}

interface InternetBrowsing {
    void browseInternet();
}

class SmartPhone extends ElectronicDevice implements Camera, MusicPlayer, InternetBrowsing {
    SmartPhone(String brand) {
        super(brand);
    }

    @Override
    public void takePhoto() {
        System.out.println(brand + " smartphone taking photo");
    }

    @Override
    public void playMusic() {
        System.out.println(brand + " smartphone playing music");
    }

    @Override
    public void browseInternet() {
        System.out.println(brand + " smartphone browsing internet");
    }

    void makeCall() {
        System.out.println(brand + " smartphone making call");
    }
}

public class InheritanceTypesDemo {
    public static void main(String[] args) {
        System.out.println("=== SINGLE INHERITANCE ===");
        Laptop laptop = new Laptop("Dell", 16);
        laptop.turnOn();
        laptop.code();

        System.out.println("\n=== MULTILEVEL INHERITANCE ===");
        Dog dog = new Dog();
        dog.eat();      // From Animal
        dog.breathe();  // From Mammal
        dog.bark();     // From Dog

        System.out.println("\n=== HIERARCHICAL INHERITANCE ===");
        Circle circle = new Circle();
        Rectangle rect = new Rectangle();
        Triangle tri = new Triangle();
        circle.draw();
        rect.draw();
        tri.draw();

        System.out.println("\n=== MULTIPLE INHERITANCE via INTERFACES ===");
        Duck duck = new Duck();
        duck.fly();
        duck.swim();
        duck.walk();
        duck.show();

        System.out.println("\n=== REAL WORLD EXAMPLE ===");
        SmartPhone phone = new SmartPhone("Samsung");
        phone.turnOn();
        phone.takePhoto();
        phone.playMusic();
        phone.browseInternet();
        phone.makeCall();

        System.out.println("\n=== WHY NO MULTIPLE INHERITANCE? ===");
        System.out.println("1. Diamond Problem: Ambiguity when two parents have same method");
        System.out.println("2. Complexity in constructor chaining");
        System.out.println("3. Type casting issues");
        System.out.println("4. Java designers chose simplicity and clarity");
        System.out.println("\nSolution: Use interfaces + default methods (Java 8+)");
    }
}
